					end

					if bedwars.AbilityController:canUseAbility('midnight') then
						local plr = entitylib.EntityPosition({
							Range = Legit.Enabled and 20 or 30,
							Part = 'RootPart',
							Players = Targets.Players.Enabled,
							NPCs = Targets.NPCs.Enabled,
