run(function()
	local AntiDizzy
	local old = nil

	AntiDizzy = vape.Categories.World:CreateModule({
		Name = 'AntiDizzy',
		Tooltip = 'no dizzy movement from mushrooms and toads',
		Function = function(callback)
			if callback then
				old = bedwars.ForestEnvironmentCollectibleEntityController.canPickupEntity
